import { useEffect, useState } from 'react';
import { docAPI, caseAPI } from '@/api';
import { FileUp, Download, Loader2, Briefcase } from 'lucide-react';

export default function Documents() {
  const [cases, setCases] = useState<any[]>([]);
  const [selectedCase, setSelectedCase] = useState<number | null>(null);
  const [docs, setDocs] = useState<any[]>([]);
  const [uploading, setUploading] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    caseAPI.getMy().then(r => {
      setCases(r.data);
      if (r.data.length > 0) { setSelectedCase(r.data[0].id); loadDocs(r.data[0].id); }
    }).finally(() => setLoading(false));
  }, []);

  const loadDocs = (caseId: number) => {
    docAPI.getByCase(caseId).then(r => setDocs(r.data));
  };

  const handleCaseChange = (caseId: number) => {
    setSelectedCase(caseId);
    loadDocs(caseId);
  };

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files?.[0] || !selectedCase) return;
    setUploading(true);
    try {
      await docAPI.upload(selectedCase, e.target.files[0]);
      loadDocs(selectedCase);
    } finally { setUploading(false); }
  };

  const handleDownload = async (docId: number, fileName: string) => {
    const res = await docAPI.download(docId);
    const url = URL.createObjectURL(res.data);
    const a = document.createElement('a'); a.href = url; a.download = fileName; a.click();
    URL.revokeObjectURL(url);
  };

  return (

      <main className=" flex-1 p-8">
        <div className="mb-6 animate-fade-in">
          <h1 className="text-2xl font-bold text-white">Documents</h1>
          <p className="text-muted-foreground mt-1">Upload and manage case documents</p>


        {loading ? (
          <div className="flex items-center justify-center py-20"><Loader2 size={28} className="animate-spin" style={{ color: '#d4a847' }} />
        ) : cases.length === 0 ? (
          <div className="glass rounded-xl p-12 text-center">
            <Briefcase size={48} className="mx-auto mb-4 text-muted-foreground opacity-40" />
            <p className="text-muted-foreground">No cases found. Documents are linked to cases.</p>

        ) : (
          <div className="space-y-5 animate-fade-in">
            <div className="glass rounded-xl p-4">
              <label className="block text-xs text-muted-foreground mb-1.5">Select Case</label>
              <select value={selectedCase || ''} onChange={e => handleCaseChange(Number(e.target.value))}
                className="w-full px-4 py-2.5 rounded-lg text-sm text-white bg-surface border border-border focus:outline-none focus:border-accent">
                {cases.map(c => <option key={c.id} value={c.id}>#{c.id} - {c.title}</option>)}
              </select>


            <label className={`flex flex-col items-center justify-center p-10 rounded-xl border-2 border-dashed cursor-pointer transition-all
              ${uploading ? 'border-accent/50 bg-accent/5' : 'border-border hover:border-accent/40 hover:bg-white/3'}`}>
              <input type="file" className="hidden" onChange={handleUpload} disabled={uploading || !selectedCase} />
              {uploading ? <Loader2 size={28} className="animate-spin mb-3" style={{ color: '#d4a847' }} /> : <FileUp size={28} className="mb-3 text-muted-foreground" />}
              <p className="font-medium text-white mb-1">{uploading ? 'Uploading...' : 'Upload Document'}</p>
              <p className="text-sm text-muted-foreground">Click to browse files</p>
            </label>

            {docs.length > 0 && (
              <div className="space-y-2">
                <h2 className="text-sm font-medium text-muted-foreground">Uploaded Documents ({docs.length})</h2>
                {docs.map(doc => (
                  <div key={doc.id} className="glass rounded-lg p-4 flex items-center justify-between hover:border-accent/30 transition-all">
                    <div className="flex items-center gap-3">
                      <div className="w-9 h-9 rounded-lg flex items-center justify-center" style={{ background: '#1e2a4a', border: '1px solid rgba(212,168,71,0.2)' }}>
                        <FileUp size={14} style={{ color: '#d4a847' }} />

                      <div>
                        <p className="text-sm font-medium text-white">{doc.fileName}</p>
                        <p className="text-xs text-muted-foreground">{new Date(doc.uploadedAt).toLocaleDateString()}</p>


                    <button onClick={() => handleDownload(doc.id, doc.fileName)}
                      className="flex items-center gap-1.5 text-xs px-3 py-1.5 rounded-lg transition-all"
                      style={{ background: 'rgba(212,168,71,0.15)', color: '#d4a847', border: '1px solid rgba(212,168,71,0.3)' }}>
                      <Download size={12} />Download
                    </button>

                ))}

            )}

        )}
      </main>

  );
}

</div>

import { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { firAPI } from '@/api';
import { Loader2, FileText, MapPin, Calendar, ArrowLeft, Briefcase } from 'lucide-react';

const statusColor: Record<string, string> = {
  PENDING: 'status-pending', UNDER_INVESTIGATION: 'status-investigation', CLOSED: 'status-closed',
};

export default function FIRDetail() {
  const { id } = useParams();
  const [fir, setFir] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    firAPI.getById(Number(id)).then(r => setFir(r.data)).finally(() => setLoading(false));
  }, [id]);

  if (loading) return (
      <main className=" flex-1 flex items-center justify-center">
        <Loader2 size={32} className="animate-spin" style={{ color: '#d4a847' }} />
      </main>

  );


  return (

      <main className=" flex-1 p-8">
        <div className="max-w-2xl mx-auto">
          <Link to="/fir/my" className="flex items-center gap-2 text-sm text-muted-foreground hover:text-white transition-colors mb-6">
            <ArrowLeft size={16} />Back to My FIRs
          </Link>
          <div className="glass rounded-xl p-6 animate-fade-in">
            <div className="flex items-start justify-between mb-5">
              <div className="flex items-center gap-3">
                <div className="w-12 h-12 rounded-xl flex items-center justify-center" style={{ background: '#1e2a4a', border: '1px solid rgba(212,168,71,0.3)' }}>
                  <FileText size={22} style={{ color: '#d4a847' }} />

                <div>
                  <h1 className="text-xl font-bold text-white">{fir.title}</h1>
                  <p className="text-sm text-muted-foreground">FIR #{fir.id}</p>


              <span className={`text-sm px-3 py-1 rounded-full ${statusColor[fir.status] || ''}`}>{fir.status}</span>

            <div className="space-y-4">
              <div>
                <p className="text-xs text-muted-foreground uppercase tracking-wider mb-1">Description</p>
                <p className="text-sm text-foreground leading-relaxed">{fir.description}</p>

              <div className="grid grid-cols-2 gap-4">
                <div className="p-3 rounded-lg bg-white/5">
                  <p className="text-xs text-muted-foreground flex items-center gap-1 mb-1"><MapPin size={10} />Location</p>
                  <p className="text-sm text-white">{fir.location || 'N/A'}</p>

                <div className="p-3 rounded-lg bg-white/5">
                  <p className="text-xs text-muted-foreground flex items-center gap-1 mb-1"><Calendar size={10} />Incident Date</p>
                  <p className="text-sm text-white">{fir.incidentDate || 'N/A'}</p>


              <div className="p-3 rounded-lg bg-white/5">
                <p className="text-xs text-muted-foreground mb-1">Submitted</p>
                <p className="text-sm text-white">{new Date(fir.createdAt).toLocaleString()}</p>




      </main>

  );
}

</div>

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { firAPI } from '@/api';
import { FileText, MapPin, Calendar, Loader2, CheckCircle, AlertCircle } from 'lucide-react';

export default function FIRForm() {
  const [form, setForm] = useState({ title: '', description: '', location: '', incidentDate: '' });
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();

