    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      await firAPI.create(form);
      setSuccess(true);
      setTimeout(() => navigate('/fir/my'), 1500);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
