          <Link to="/legal" className="flex items-center gap-2 text-sm text-muted-foreground hover:text-white transition-colors mb-6">
            <ArrowLeft size={16} />Back to Legal Sections
          </Link>

          <div className="glass rounded-xl p-6 animate-fade-in">
            <div className="flex items-start gap-4 mb-6">
              <div className="w-14 h-14 rounded-xl flex items-center justify-center"
                   style={{ background: '#1e2a4a', border: '1px solid rgba(212,168,71,0.3)' }}>
                <Scale size={24} style={{ color: '#d4a847' }} />

              <div>
                <div className="flex items-center gap-2 mb-1">
                  <h1 className="text-2xl font-bold text-white">{section.code}</h1>
                  <span className="text-xs px-2 py-0.5 rounded-full text-white"
                        style={{ background: section.actType === 'IPC' ? 'rgba(59,130,246,0.4)' : 'rgba(168,85,247,0.4)' }}>
                    {section.actType}
                  </span>

                <p className="text-lg text-foreground">{section.title}</p>



            <div className="space-y-4">
              <div className="p-4 rounded-lg bg-white/5">
