import { useEffect, useState } from 'react';
import { notifAPI } from '@/api';
import { Bell, Send, Loader2, CheckCircle, Users } from 'lucide-react';

export default function AdminNotifications() {
  const [notifs, setNotifs] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({ userId: '', message: '' });
  const [submitting, setSubmitting] = useState(false);
  const [msg, setMsg] = useState('');
  const [recent, setRecent] = useState<any[]>([]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitting(true);
    try {
      if (form.userId) await notifAPI.send(Number(form.userId), form.message);
      else await notifAPI.broadcast(form.message);
      setForm({ userId: '', message: '' });
      setMsg('Notification sent!'); setTimeout(() => setMsg(''), 2000);
    } finally { setSubmitting(false); }
  };

  return (

      <main className=" flex-1 p-8">
        <div className="mb-6 animate-fade-in">
          <h1 className="text-2xl font-bold text-white">Send Notifications</h1>
          <p className="text-muted-foreground mt-1">Send targeted or broadcast notifications to users</p>


        <div className="max-w-xl">
          <div className="glass rounded-xl p-6 animate-fade-in">
            <h2 className="font-semibold text-white mb-4 flex items-center gap-2">
              <Send size={16} style={{ color: '#d4a847' }} />Compose Notification
            </h2>
            {msg && (
              <div className="mb-4 p-3 rounded-lg flex items-center gap-2 text-sm text-green-400 bg-green-500/10 border border-green-500/20">
                <CheckCircle size={16} />{msg}

            )}
            <form onSubmit={handleSend} className="space-y-4">
              <div>
                <label className="block text-xs text-muted-foreground mb-1.5 flex items-center gap-1">
                  <Users size={12} />User ID (leave blank for broadcast)
                </label>
                <input type="number" value={form.userId} onChange={e => setForm(f => ({ ...f, userId: e.target.value }))}
                  className="w-full px-4 py-2.5 rounded-lg text-sm text-white bg-white/5 border border-border focus:outline-none focus:border-accent transition-all"
                  placeholder="Enter user ID or leave empty for all users" />

              <div>
                <label className="block text-xs text-muted-foreground mb-1.5">Message *</label>
                <textarea value={form.message} onChange={e => setForm(f => ({ ...f, message: e.target.value }))} required rows={4}
                  className="w-full px-4 py-2.5 rounded-lg text-sm text-white bg-white/5 border border-border focus:outline-none focus:border-accent transition-all resize-none"
                  placeholder="Write your notification message..." />

              <button type="submit" disabled={submitting}
                className="w-full py-3 rounded-lg text-sm font-semibold flex items-center justify-center gap-2 disabled:opacity-60"
                style={{ background: 'linear-gradient(135deg, #d4a847, #c49437)', color: '#0f172a' }}>
                {submitting ? <><Loader2 size={14} className="animate-spin" />Sending...</> : <><Bell size={14} />{form.userId ? 'Send to User' : 'Broadcast to All'}</>}
              </button>
            </form>


      </main>

  );
}

</div>

import { useEffect, useState } from 'react';
import { firAPI, caseAPI, notifAPI } from '@/api';
import { Briefcase, FileText, Shield, Loader2 } from 'lucide-react';

function StatCard({ label, value, icon: Icon, color, delay }: any) {
  return (
    <div className="glass rounded-xl p-5 animate-fade-in" style={{ animationDelay: delay }}>
      <div className="flex items-center justify-between mb-3">
        <p className="text-sm text-muted-foreground">{label}</p>
        <div className="w-9 h-9 rounded-lg flex items-center justify-center" style={{ background: `${color}20`, border: `1px solid ${color}30` }}>
          <Icon size={18} style={{ color }} />


      <p className="text-3xl font-bold text-white">{value}</p>

  );
}

export default function AdminPanel() {
  const [firs, setFirs] = useState<any[]>([]);
  const [cases, setCases] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([firAPI.getAll(), caseAPI.getAll()])
      .then(([f, c]) => { setFirs(f.data); setCases(c.data); })
      .finally(() => setLoading(false));
  }, []);

  if (loading) return (
      <main className=" flex-1 flex items-center justify-center">
        <Loader2 size={32} className="animate-spin" style={{ color: '#d4a847' }} />
      </main>

  );

  return (

      <main className=" flex-1 p-8">
        <div className="mb-8 animate-fade-in">
          <div className="flex items-center gap-3 mb-1">
            <Shield size={22} style={{ color: '#d4a847' }} />
            <h1 className="text-2xl font-bold text-white">Admin Control Panel</h1>

          <p className="text-muted-foreground">Overview of the entire Legal FIR system</p>


        <div className="grid grid-cols-4 gap-4 mb-8">
          <StatCard label="Total FIRs" value={firs.length} icon={FileText} color="#3b82f6" delay="0s" />
          <StatCard label="Pending FIRs" value={firs.filter(f => f.status === 'PENDING').length} icon={FileText} color="#f59e0b" delay="0.1s" />
          <StatCard label="Active Cases" value={cases.filter(c => c.status !== 'CLOSED').length} icon={Briefcase} color="#d4a847" delay="0.2s" />
          <StatCard label="Closed Cases" value={cases.filter(c => c.status === 'CLOSED').length} icon={Briefcase} color="#22c55e" delay="0.3s" />


        {/* Recent FIRs Table */}
        <div className="glass rounded-xl p-5 animate-fade-in mb-6">
          <h2 className="font-semibold text-white mb-4 flex items-center gap-2"><FileText size={16} style={{ color: '#d4a847' }} />Recent FIRs</h2>
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-border">
                <th className="text-left py-2 text-muted-foreground font-medium">ID</th>
                <th className="text-left py-2 text-muted-foreground font-medium">Title</th>
                <th className="text-left py-2 text-muted-foreground font-medium">Submitted By</th>
                <th className="text-left py-2 text-muted-foreground font-medium">Status</th>
                <th className="text-left py-2 text-muted-foreground font-medium">Date</th>
              </tr>
            </thead>
            <tbody>
              {firs.slice(0, 8).map(fir => (
                <tr key={fir.id} className="border-b border-border/50 hover:bg-white/3 transition-colors">
                  <td className="py-2.5 text-muted-foreground">#{fir.id}</td>
                  <td className="py-2.5 text-white font-medium">{fir.title}</td>
                  <td className="py-2.5 text-muted-foreground">{fir.userName || 'N/A'}</td>
                  <td className="py-2.5">
                    <span className={`text-xs px-2 py-0.5 rounded-full ${fir.status === 'PENDING' ? 'status-pending' : fir.status === 'UNDER_INVESTIGATION' ? 'status-investigation' : 'status-closed'}`}>
                      {fir.status}
                    </span>
                  </td>
                  <td className="py-2.5 text-muted-foreground">{new Date(fir.createdAt).toLocaleDateString()}</td>
                </tr>
              ))}
            </tbody>
          </table>

      </main>

  );
}

</div>

import { useEffect, useState } from 'react';
import { reportAPI } from '@/api';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';
import { BarChart2, Loader2, FileText, Briefcase, Users, TrendingUp } from 'lucide-react';

const COLORS = ['#d4a847', '#3b82f6', '#22c55e', '#ef4444', '#a855f7'];

export default function AdminReports() {
  const [summary, setSummary] = useState<any>(null);
  const [firStats, setFirStats] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([reportAPI.getSummary(), reportAPI.getFirStats()])
      .then(([s, f]) => { setSummary(s.data); setFirStats(f.data); })
      .finally(() => setLoading(false));
  }, []);

  if (loading) return (
      <main className=" flex-1 flex items-center justify-center">
        <Loader2 size={32} className="animate-spin" style={{ color: '#d4a847' }} />
      </main>

  );

  const pieData = firStats.map(f => ({ name: f.status, value: f.count }));

  return (

      <main className=" flex-1 p-8">
        <div className="mb-6 animate-fade-in">
          <h1 className="text-2xl font-bold text-white flex items-center gap-2"><BarChart2 size={22} style={{ color: '#d4a847' }} />Reports & Analytics</h1>
          <p className="text-muted-foreground mt-1">System-wide statistics and insights</p>


        {summary && (
          <div className="grid grid-cols-4 gap-4 mb-8 animate-fade-in">
            {[
              { label: 'Total FIRs', value: summary.totalFIRs, icon: FileText, color: '#3b82f6' },
              { label: 'Total Cases', value: summary.totalCases, icon: Briefcase, color: '#d4a847' },
              { label: 'Total Users', value: summary.totalUsers, icon: Users, color: '#a855f7' },
              { label: 'Pending FIRs', value: summary.pendingFIRs, icon: TrendingUp, color: '#f59e0b' },
            ].map((s, i) => (
              <div key={s.label} className="glass rounded-xl p-5" style={{ animationDelay: `${i * 0.1}s` }}>
                <div className="flex items-center justify-between mb-3">
                  <p className="text-sm text-muted-foreground">{s.label}</p>
                  <s.icon size={18} style={{ color: s.color }} />

                <p className="text-3xl font-bold text-white">{s.value ?? '—'}</p>

            ))}

        )}

        <div className="grid grid-cols-2 gap-6">
          {/* FIR Status Bar Chart */}
          {firStats.length > 0 && (
            <div className="glass rounded-xl p-5 animate-fade-in">
              <h2 className="font-semibold text-white mb-4">FIR Status Distribution</h2>
              <ResponsiveContainer width="100%" height={220}>
                <BarChart data={firStats} margin={{ top: 0, right: 0, left: -10, bottom: 0 }}>
                  <XAxis dataKey="status" tick={{ fill: '#94a3b8', fontSize: 11 }} axisLine={false} tickLine={false} />
                  <YAxis tick={{ fill: '#94a3b8', fontSize: 11 }} axisLine={false} tickLine={false} />
                  <Tooltip contentStyle={{ background: '#1e293b', border: '1px solid #334155', borderRadius: '8px' }} labelStyle={{ color: '#fff' }} />
                  <Bar dataKey="count" radius={[4, 4, 0, 0]}>
                    {firStats.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>

          )}

          {/* Pie Chart */}
          {pieData.length > 0 && (
            <div className="glass rounded-xl p-5 animate-fade-in">
              <h2 className="font-semibold text-white mb-4">FIR Status Breakdown</h2>
              <ResponsiveContainer width="100%" height={220}>
                <PieChart>
                  <Pie data={pieData} cx="50%" cy="50%" outerRadius={80} dataKey="value" label={(props: any) => `${props.name} ${((props.percent ?? 0) * 100).toFixed(0)}%`} labelLine={false}>
                    {pieData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                  </Pie>
                  <Tooltip contentStyle={{ background: '#1e293b', border: '1px solid #334155', borderRadius: '8px' }} />
                </PieChart>
              </ResponsiveContainer>

          )}

      </main>

  );
}

</div>

